// Tokens de cor das variações (alinhados ao DSS)
const VARIANTS = {
  default: {
    readerColor: "#a4a6a5",
    sansysColor: "#a4a6a5",
    iconColor: "#a4a6a5",
  },
  colored: {
    readerColor: "#60151d", // borgonha/vinho
    sansysColor: "#1d4971", // azul
    iconColor: "#60151d", // borgonha/vinho (mesmo tom do Reader)
  },
} as const;

export type LogoVariant = keyof typeof VARIANTS;

export interface SansysReaderLogoProps {
  className?: string;
  /** Preset de cores. 'default' = monocromático neutro, 'colored' = cores da marca. */
  variant?: LogoVariant;
  /**
   * Cor do wordmark "Reader".
   * Sobrepõe a cor definida pelo variant.
   */
  readerColor?: string;
  /**
   * Cor do wordmark "Sansys".
   * Sobrepõe a cor definida pelo variant.
   */
  sansysColor?: string;
  /**
   * Cor do ícone.
   * Sobrepõe a cor definida pelo variant.
   */
  iconColor?: string;
  /**
   * @deprecated Use `readerColor` + `sansysColor` + `iconColor` para controle granular,
   * ou `variant` para presets. Mantido por compatibilidade.
   */
  color?: string;
}

export function SansysReaderLogo({
  className = "h-12",
  variant = "default",
  readerColor,
  sansysColor,
  iconColor,
  color, // legacy
}: SansysReaderLogoProps) {
  const base = VARIANTS[variant];

  // Resolução de cor: prop explícita > legacy `color` > valor do variant
  const resolvedReader = readerColor ?? color ?? base.readerColor;
  const resolvedSansys = sansysColor ?? color ?? base.sansysColor;
  const resolvedIcon = iconColor ?? color ?? base.iconColor;

  return (
    <svg
      className={className}
      viewBox="0 0 149 42"
      xmlns="http://www.w3.org/2000/svg"
      aria-label="Sansys Reader"
      role="img"
    >
      <g>
        {/* Wordmark: Reader */}
        <path fill={resolvedReader} d={READER_PATH} />

        {/* Wordmark: Sansys */}
        <path fill={resolvedSansys} d={SANSYS_PATH} />

        {/* Ícone - Shape 1 com opacidade 0.6 */}
        <path fill={resolvedIcon} fillOpacity={0.6} d={ICON_SHAPE1_PATH} />

        {/* Ícone - Shape 2 com opacidade 0.7 */}
        <path fill={resolvedIcon} fillOpacity={0.7} d={ICON_SHAPE2_PATH} />
      </g>
    </svg>
  );
}
